def fibonacci_dp(n):
    # Create a dictionary to store calculated fibonacci numbers
    fib_dict = {}

    # Base cases
    fib_dict[0] = 0
    fib_dict[1] = 1

    # Function to calculate the nth fibonacci number using dynamic programming
    def fibonacci_dp_helper(n):
